    ('guilherme-derrite', 'PL', '1148', 2021, 'Altera o inciso XIV do art. 6º da Lei nº 7.713, de 22 de dezembro de 1988, para determinar que a isenção do Imposto sobre a Renda das Pessoas Físicas seja estendida àqueles que tenham dependente sem rendimentos tributáveis sujeitos ao ajuste anual, portador das doenças relacionadas, e para que recaia, além de proventos de aposentadoria ou reforma, sobre salários, remunerações e verbas indenizatórias de qualquer natureza, nos termos estipulados.', 'Camara', '2275983', 'https://dadosabertos.camara.leg.br/api/v2/proposicoes/2275983', 'guilherme-derrite-camara-completo-autoria-principal-tipos-legislativos-2019-2024-cutoff-20260509', 'inventario_completo_scoped_camara_autoria_principal_tipos_legislativos_2019_2024_cutoff_20260509', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","slug":"guilherme-derrite","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"guilherme-derrite-camara-completo-scoped-bloco1-20260509","coverage_id":"guilherme-derrite-camara-completo-autoria-principal-tipos-legislativos-2019-2024-cutoff-20260509","coverage_scope":"inventario_completo_scoped_camara_autoria_principal_tipos_legislativos_2019_2024_cutoff_20260509","coverage_status":"completo_scoped","coverage_policy":"camara_autoria_principal_tipo_legislativo_canonico_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos legislativos canonicos","cutoff":"2026-05-09","source_artifact":"fonte interna de curadoria","camara_id_deputado":204531,"proposicao_id_api":"2275983","data_apresentacao":null,"detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2275983","autores_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2275983/autores","public_url":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2275983","autor_nome":null,"autor_tipo":null,"autor_uri":null,"ordem_assinatura":null,"proponente":null,"autoria_prin