    ('guilherme-derrite', 'PL', '2681', 2020, 'Acrescenta os parágrafos 6º e 7º ao art. 392 e altera o art. 392-B, do Decreto-Lei nº 5.452, de 1ª de maio de 1943, Consolidação das Leis do Trabalho, para estabelecer que o marco inicial da licença-maternidade e do respectivo salário-maternidade seja a alta hospitalar da genitora e/ou do recém-nascido, o que ocorrer por último, bem como para assegurar àquele que conste como genitor na certidão de nascimento, se empregado, o gozo de licença por todo o período ou pelo tempo restante da licença-maternidade que teria a genitora acometida por incapacidade física ou psíquica.', 'Camara', '2252783', 'https://dadosabertos.camara.leg.br/api/v2/proposicoes/2252783', 'guilherme-derrite-camara-completo-autoria-principal-tipos-legislativos-2019-2024-cutoff-20260509', 'inventario_completo_scoped_camara_autoria_principal_tipos_legislativos_2019_2024_cutoff_20260509', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","slug":"guilherme-derrite","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"guilherme-derrite-camara-completo-scoped-bloco1-20260509","coverage_id":"guilherme-derrite-camara-completo-autoria-principal-tipos-legislativos-2019-2024-cutoff-20260509","coverage_scope":"inventario_completo_scoped_camara_autoria_principal_tipos_legislativos_2019_2024_cutoff_20260509","coverage_status":"completo_scoped","coverage_policy":"camara_autoria_principal_tipo_legislativo_canonico_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos legislativos canonicos","cutoff":"2026-05-09","source_artifact":"fonte interna de curadoria","camara_id_deputado":204531,"proposicao_id_api":"2252783","data_apresentacao":null,"detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2252783","autores_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2252783/autores","public_url":"https://dadosabertos.camara.leg.br/api/v2/