    ('guilherme-derrite', 'PL', '2217', 2019, 'Altera o art. 16 da Lei n° 11.340, de 7 de agosto de 2006, a chamada "Lei Maria da Penha", para garantir a persecução penal através de ação penal pública incondicionada em todos os casos de crimes de violência doméstica e familiar contra a mulher, à exceção dos crimes contra a honra, nos quais, para as ações penais privadas nesse contexto, só serão admitidas a reconciliação, renúncia ou o perdão, perante o juiz, em audiência especialmente designada com tal finalidade, e ouvido o Ministério Público.', 'Camara', '2197607', 'https://dadosabertos.camara.leg.br/api/v2/proposicoes/2197607', 'guilherme-derrite-camara-completo-autoria-principal-tipos-legislativos-2019-2024-cutoff-20260509', 'inventario_completo_scoped_camara_autoria_principal_tipos_legislativos_2019_2024_cutoff_20260509', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","slug":"guilherme-derrite","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"guilherme-derrite-camara-completo-scoped-bloco1-20260509","coverage_id":"guilherme-derrite-camara-completo-autoria-principal-tipos-legislativos-2019-2024-cutoff-20260509","coverage_scope":"inventario_completo_scoped_camara_autoria_principal_tipos_legislativos_2019_2024_cutoff_20260509","coverage_status":"completo_scoped","coverage_policy":"camara_autoria_principal_tipo_legislativo_canonico_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos legislativos canonicos","cutoff":"2026-05-09","source_artifact":"fonte interna de curadoria","camara_id_deputado":204531,"proposicao_id_api":"2197607","data_apresentacao":null,"detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2197607","autores_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2197607/autores","public_url":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2197607","autor_nome":null,"autor_tipo":null,"autor_uri":null,