    ('guilherme-derrite', 'PL', '1137', 2019, 'Acrescenta o parágrafo único ao art. 24 doDecreto-Lei nº 667, de 2 de julho de 1969, para assegurar aos bombeiros militares um parâmetro máximo ao regime ordinário de trabalho operacional de 3 (três) horas de descanso para cada 1 (uma) hora trabalhada e para inserir uma limitação máxima de horas trabalhadas de modo ininterrupto a 24 (vinte e quatro) horas.', 'Camara', '2193151', 'https://dadosabertos.camara.leg.br/api/v2/proposicoes/2193151', 'guilherme-derrite-camara-completo-autoria-principal-tipos-legislativos-2019-2024-cutoff-20260509', 'inventario_completo_scoped_camara_autoria_principal_tipos_legislativos_2019_2024_cutoff_20260509', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","slug":"guilherme-derrite","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"guilherme-derrite-camara-completo-scoped-bloco1-20260509","coverage_id":"guilherme-derrite-camara-completo-autoria-principal-tipos-legislativos-2019-2024-cutoff-20260509","coverage_scope":"inventario_completo_scoped_camara_autoria_principal_tipos_legislativos_2019_2024_cutoff_20260509","coverage_status":"completo_scoped","coverage_policy":"camara_autoria_principal_tipo_legislativo_canonico_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos legislativos canonicos","cutoff":"2026-05-09","source_artifact":"fonte interna de curadoria","camara_id_deputado":204531,"proposicao_id_api":"2193151","data_apresentacao":null,"detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2193151","autores_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2193151/autores","public_url":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2193151","autor_nome":null,"autor_tipo":null,"autor_uri":null,"ordem_assinatura":null,"proponente":null,"autoria_principal_verificada":false,"tipo_legislativo_canonico":true,"exists_in_projetos_lei_before_re