    ('capitao-wagner', 'PL', '3657', 2021, 'Altera a Lei nº 11.977, de 7 de julho de 2009, e a Lei nº 14.118, de 12 de janeiro de 2021, para garantir aos beneficiários do Programa Minha Casa Minha Vida - PMCMV e do Programa Casa Verde e Amarela, que tenham sido expulsos de suas residências ou estejam sob ameaça de organizações criminosas, o direito à rescisão contratual, com a consequente restituição das prestações pagas, ou de serem contemplados de imediato com outra unidade habitacional já existente dos referidos programas, ainda que de forma temporária, assegurado o direito do beneficiário à opção por uma unidade definitiva.', 'Camara', '2303343', 'https://www.camara.leg.br/proposicoesWeb/fichadetramitacao?idProposicao=2303343', 'capitao-wagner-camara-completo-autoria-principal-tipos-legislativos-2019-2022-cutoff-20260509', 'inventario_completo_scoped_camara_autoria_principal_tipos_legislativos_2019_2022_cutoff_20260509', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","slug":"capitao-wagner","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"capitao-wagner-camara-completo-scoped-bloco1-20260509","coverage_id":"capitao-wagner-camara-completo-autoria-principal-tipos-legislativos-2019-2022-cutoff-20260509","coverage_scope":"inventario_completo_scoped_camara_autoria_principal_tipos_legislativos_2019_2022_cutoff_20260509","coverage_status":"completo_scoped","coverage_policy":"camara_autoria_principal_tipo_legislativo_canonico_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos legislativos canonicos","cutoff":"2026-05-09","source_artifact":"fonte interna de curadoria","camara_id_deputado":204487,"proposicao_id_api":"2303343","data_apresentacao":"2021-10-19T12:27","detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2303343","autores_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2303343/autores","public_url":"https://www