    ('capitao-wagner', 'PL', '1561', 2020, 'Institui a "Loteria da Saúde", como nova modalidade de loteria de prognósticos numéricos, com destinação dos recursos do produto de sua arrecadação para o Sistema Único de Saúde - SUS e, excepcionalmente, para as ações de prevenção, contenção, combate e mitigação dos efeitos da Pandemia do Novo Coronavírus (Covid-19), enquanto durarem os efeitos do Estado de Calamidade Pública, declarado pelo Decreto-Legislativo nº 6, de 2020. NOVA EMENTA: Autoriza o Poder Executivo a instituir os produtos lotéricos denominados Loteria da Saúde e Loteria do Turismo; e altera a Lei nº 13.756, de 12 de dezembro de 2018', 'Camara', '2243079', 'https://www.camara.leg.br/proposicoesWeb/fichadetramitacao?idProposicao=2243079', 'capitao-wagner-camara-completo-autoria-principal-tipos-legislativos-2019-2022-cutoff-20260509', 'inventario_completo_scoped_camara_autoria_principal_tipos_legislativos_2019_2022_cutoff_20260509', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","slug":"capitao-wagner","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"capitao-wagner-camara-completo-scoped-bloco1-20260509","coverage_id":"capitao-wagner-camara-completo-autoria-principal-tipos-legislativos-2019-2022-cutoff-20260509","coverage_scope":"inventario_completo_scoped_camara_autoria_principal_tipos_legislativos_2019_2022_cutoff_20260509","coverage_status":"completo_scoped","coverage_policy":"camara_autoria_principal_tipo_legislativo_canonico_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos legislativos canonicos","cutoff":"2026-05-09","source_artifact":"fonte interna de curadoria","camara_id_deputado":204487,"proposicao_id_api":"2243079","data_apresentacao":"2020-04-03T22:43","detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2243079","autores_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2243079/autores","public_u