    ('erika-hilton', 'PLP', '242', 2025, 'Altera a Lei nº 4.320, de 17 de março de 1964, e a Lei Complementar nº 101, de 4 de maio de 2000, para tratar do Orçamento Sensível ao Clima, determinando a classificação das despesas, de forma direta e indireta, de acordo com seu impacto no enfrentamento da emergência climática e do racismo ambiental, na redução das emissões de gases de efeito estufa e iniciativas de mitigação e adaptação climática, de modo a excetuar essas despesas de medidas de limitação de empenho e movimentação financeira.', 'Camara', '2585266', 'https://www.camara.leg.br/proposicoesWeb/fichadetramitacao?idProposicao=2585266', 'erika-hilton-camara-completo-autoria-principal-tipos-legislativos-2023-2026-cutoff-20260509', 'inventario_completo_scoped_camara_autoria_principal_tipos_legislativos_2023_2026_cutoff_20260509', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","slug":"erika-hilton","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"erika-hilton-camara-completo-scoped-bloco1-20260509","coverage_id":"erika-hilton-camara-completo-autoria-principal-tipos-legislativos-2023-2026-cutoff-20260509","coverage_scope":"inventario_completo_scoped_camara_autoria_principal_tipos_legislativos_2023_2026_cutoff_20260509","coverage_status":"completo_scoped","coverage_policy":"camara_autoria_principal_tipo_legislativo_canonico_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos legislativos canonicos","cutoff":"2026-05-09","source_artifact":"fonte interna de curadoria","camara_id_deputado":220645,"proposicao_id_api":"2585266","data_apresentacao":"2025-11-14T18:26","detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2585266","autores_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2585266/autores","public_url":"https://www.camara.leg.br/proposicoesWeb/fichadetramitacao?idProposicao=2585266","autor_nome":"Erika Hilton","aut