    ('erika-hilton', 'PL', '475', 2024, 'Institui direitos para o combate à discriminação de gestantes e parturientes e de pessoas que exercem cuidado de uma ou mais crianças e que sejam candidatas em processos seletivos de bolsas de graduação e pós-graduação. NOVA EMENTA: Veda a adoção de critérios discriminatórios contra estudantes e pesquisadores em virtude de gestação, de parto, de nascimento de filho ou de adoção ou obtenção de guarda judicial para fins de adoção nos processos de seleção para bolsas de estudo e pesquisa das instituições de educação superior e das agências de fomento à pesquisa.', 'Camara', '2418789', 'https://www.camara.leg.br/proposicoesWeb/fichadetramitacao?idProposicao=2418789', 'erika-hilton-camara-completo-autoria-principal-tipos-legislativos-2023-2026-cutoff-20260509', 'inventario_completo_scoped_camara_autoria_principal_tipos_legislativos_2023_2026_cutoff_20260509', '{"source":"Camara Dados Abertos","data_real":true,"fluxo":"Legislacao full-site","slug":"erika-hilton","tabela_alvo":"projetos_lei","legislacao_mandato_executivo_mixed":false,"curation_batch_id":"erika-hilton-camara-completo-scoped-bloco1-20260509","coverage_id":"erika-hilton-camara-completo-autoria-principal-tipos-legislativos-2023-2026-cutoff-20260509","coverage_scope":"inventario_completo_scoped_camara_autoria_principal_tipos_legislativos_2023_2026_cutoff_20260509","coverage_status":"completo_scoped","coverage_policy":"camara_autoria_principal_tipo_legislativo_canonico_v1","recorte_publico":"autoria parlamentar principal na Camara dos Deputados em tipos legislativos canonicos","cutoff":"2026-05-09","source_artifact":"fonte interna de curadoria","camara_id_deputado":220645,"proposicao_id_api":"2418789","data_apresentacao":"2024-02-28T10:30","detalhe_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2418789","autores_endpoint":"https://dadosabertos.camara.leg.br/api/v2/proposicoes/2418789/autores","public_url":"https://www.camara.leg.br/proposicoesWeb/fichade