DO $$
DECLARE
  rec record;
  cand_id uuid;
  lme_count int;
  divergent_target_count int;
BEGIN
  FOR rec IN SELECT * FROM _legislacao_bloco1_camara_completo_expected LOOP
    SELECT id INTO cand_id FROM candidatos WHERE slug = rec.slug;

    IF cand_id IS NULL THEN
      RAISE NOTICE '%: candidato ausente neste banco local/CI minimo; seed completo scoped pulado', rec.slug;
      CONTINUE;
    END IF;

    SELECT count(*) INTO lme_count
    FROM legislacao_mandato_executivo
    WHERE candidato_id = cand_id;

    IF lme_count <> 0 THEN
      RAISE EXCEPTION 'Pre-condicao %: legislacao_mandato_executivo deve permanecer 0, encontrado %', rec.slug, lme_count;
    END IF;

    SELECT count(*) INTO divergent_target_count
    FROM projetos_lei pl
    JOIN _legislacao_bloco1_camara_completo_seed seed
      ON seed.slug = rec.slug
     AND seed.proposicao_id_api = pl.proposicao_id_api
    WHERE pl.candidato_id = cand_id
      AND pl.coverage_id IS NOT NULL
      AND pl.coverage_id <> rec.coverage_id
      AND pl.coverage_id NOT LIKE rec.slug || '-camara-autoria-principal-ampliado-parcial%';

    IF divergent_target_count <> 0 THEN
      RAISE EXCEPTION 'Pre-condicao %: % rows alvo ja tem coverage_id divergente nao esperado', rec.slug, divergent_target_count;
    END IF;
  END LOOP;
END $$;

WITH target AS (
  SELECT c.id AS candidato_id, c.slug
  FROM candidatos c
  JOIN _legislacao_bloco1_camara_completo_expected e ON e.slug = c.slug
)
INSERT INTO projetos_lei (
  candidato_id,
  tipo,
  numero,
  ano,
  ementa,
  fonte,
  proposicao_id_api,
  url_inteiro_teor,
  coverage_id,
  coverage_scope,
  metadata
)
SELECT
  target.candidato_id,
  seed.tipo,
  seed.numero,
  seed.ano,
  seed.ementa,
  seed.fonte,
  seed.proposicao_id_api,
  seed.url_inteiro_teor,
  seed.coverage_id,
  seed.coverage_scope,
  seed.metadata
FROM _legislacao_bloco1_camara_completo_seed seed
JOIN target ON target.slug = seed.slug
ON CONFLICT (candidato_id, proposicao_id_api) DO UPDATE SET
  tipo = EXCLUDED.tipo,
  numero = EXCLUDED.numero,
  ano = EXCLUDED.ano,
  ementa = EXCLUDED.ementa,
  fonte = EXCLUDED.fonte,
  url_inteiro_teor = EXCLUDED.url_inteiro_teor,
  coverage_id = EXCLUDED.coverage_id,
  coverage_scope = EXCLUDED.coverage_scope,
  metadata = COALESCE(projetos_lei.metadata, '{}'::jsonb) || EXCLUDED.metadata
WHERE projetos_lei.coverage_id IS NULL
   OR projetos_lei.coverage_id = EXCLUDED.coverage_id
   OR projetos_lei.coverage_id LIKE ((EXCLUDED.metadata->>'slug') || '-camara-autoria-principal-ampliado-parcial%');

DO $$
DECLARE
  rec record;
  cand_id uuid;
  coverage_count int;
  scope_count int;
  lme_count int;
  other_slug_count int;
BEGIN
  FOR rec IN SELECT * FROM _legislacao_bloco1_camara_completo_expected LOOP
    SELECT id INTO cand_id FROM candidatos WHERE slug = rec.slug;

    IF cand_id IS NULL THEN
      RAISE NOTICE '%: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo', rec.slug;
      CONTINUE;
    END IF;

    SELECT count(*) INTO coverage_count
    FROM projetos_lei
    WHERE candidato_id = cand_id
      AND coverage_id = rec.coverage_id;

    SELECT count(*) INTO scope_count
    FROM projetos_lei
    WHERE candidato_id = cand_id
      AND coverage_id = rec.coverage_id
      AND coverage_scope = rec.coverage_scope
      AND metadata->>'coverage_status' = 'completo_scoped'
      AND metadata->>'tabela_alvo' = 'projetos_lei'
      AND metadata->>'legislacao_mandato_executivo_mixed' = 'false';

    SELECT count(*) INTO lme_count
    FROM legislacao_mandato_executivo
    WHERE candidato_id = cand_id;

    SELECT count(*) INTO other_slug_count
    FROM projetos_lei
    WHERE candidato_id <> cand_id
      AND coverage_id = rec.coverage_id;

    IF coverage_count <> rec.expected_rows THEN
      RAISE EXCEPTION 'Pos-apply %: esperadas % rows com coverage_id completo scoped, encontradas %', rec.slug, rec.expected_rows, coverage_count;
    END IF;

    IF scope_count <> rec.expected_rows THEN
      RAISE EXCEPTION 'Pos-apply %: esperadas % rows com metadata/scope completo scoped, encontradas %', rec.slug, rec.expected_rows, scope_count;
    END IF;

    IF lme_count <> 0 THEN
      RAISE EXCEPTION 'Pos-apply %: legislacao_mandato_executivo deve permanecer 0, encontrado %', rec.slug, lme_count;
    END IF;

    IF other_slug_count <> 0 THEN
      RAISE EXCEPTION 'Pos-apply %: % rows de outros slugs com coverage_id alvo', rec.slug, other_slug_count;
    END IF;
  END LOOP;
END $$;
